def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -2):
                for b in range(1, a + 4):
                    temp = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    priority += temp * np.sin(ratio * b / (a + 2)) * np.tanh(b / (a + 1))
            priority += (np.exp(ratio - 8) * np.cos(ratio * 1.3)) ** 2
            if i % 2 == 0:
                priority -= np.log1p(bin_cap) * 3
            else:
                priority += np.sqrt(bin_cap) * 2.5
        elif 5 < ratio <= 8:
            for c in range(1, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 3):
                    term = ((ratio - c) ** 4) * np.cos(ratio * d) / (d + 1)
                    priority += np.tanh(term) * 1.5 * np.cos(i * 0.5)
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3.5
            if bin_cap > item * 5:
                priority -= np.exp(-1.5 * ratio) * 5
            else:
                priority += np.sin(ratio * 2) * 3
        elif 2 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for e in range(1, 15):
                s1 += ((ratio - 2) ** e) / (e * 2.1) * np.cos(e * ratio / 1.5)
                if e % 2 == 0:
                    s2 += ((ratio - 2) ** e) / (e * 1.5) * np.sin(e * ratio)
            priority = (s1 * np.cos(9 * ratio) + s2 * np.sin(5 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            if bin_cap < item * 1.5:
                priority += np.exp(-ratio) * 4
            else:
                priority -= np.log1p(bin_cap) * 2
        elif 1 <= ratio < 2:
            s = 0
            penalty = 0
            for f in range(1, 12):
                s += ((2 - ratio) ** f) / (f ** 2 + 1) * np.sin(f * ratio * 1.1)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i * 0.5) * ((ratio - 1) ** g) / (g + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 20):
                s += ((1 - ratio) ** h) / (h * 3.5)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
            if bin_cap < item * 0.9:
                priority += np.tanh(ratio) * 3
            else:
                priority -= np.exp(-ratio * 2.2) * 2
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 17):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.3)
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.2 - ratio) ** m) / (m * 6) * np.sin(m * item * 1.0)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 8) * np.cos(item * n * 0.85)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
